266	
267	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context) {
268	        (
269	            State::Idle,
270	            Context {
271	                value: if let Some(value) = &props.value {
272	                    Bindable::controlled(value.clone())
273	                } else {
274	                    Bindable::uncontrolled(props.default_value.clone())
275	                },
276	                feedback_duration_ms: props.feedback_duration_ms,
277	                disabled: props.disabled,
278	                error: None,
279	                locale: env.locale.clone(),
280	                messages: messages.clone(),
281	                ids: ComponentIds::from_id(&props.id),
282	            },
283	        )
284	    }
285	
286	    fn transition(
287	        state: &Self::State,
288	        event: &Self::Event,
289	        _ctx: &Self::Context,
290	        props: &Self::Props,
291	    ) -> Option<TransitionPlan<Self>> {
292	        match (state, event) {
293	            (_, Event::Copy) if props.disabled => None,
294	
295	            (State::Idle, Event::Copy) => Some(copying_plan()),
296	
297	            (State::Copied | State::Error, Event::Copy) => {
298	                Some(copying_plan().cancel_effect(Effect::FeedbackTimer))
299	            }
300	
301	            (State::Copying, Event::CopySuccess) => Some(
302	                TransitionPlan::to(State::Copied)
303	                    .apply(|ctx: &mut Context| {
304	                        ctx.error = None;
305	                    })
306	                    .with_effect(PendingEffect::named(Effect::AnnounceCopied))
307	                    .with_effect(PendingEffect::named(Effect::FeedbackTimer)),
308	            ),
309	
310	            (State::Copying, Event::CopyError(reason)) => {
311	                let reason = reason.clone();
312	                Some(
313	                    TransitionPlan::to(State::Error)
314	                        .apply(move |ctx: &mut Context| {
315	                            ctx.error = Some(reason);
316	                        })
317	                        .with_effect(PendingEffect::named(Effect::AnnounceError))
318	                        .with_effect(PendingEffect::named(Effect::FeedbackTimer)),
319	                )
320	            }
321	
322	            (State::Copied | State::Error, Event::ResetTimeout) => {
323	                Some(TransitionPlan::to(State::Idle).apply(|ctx: &mut Context| {
324	                    ctx.error = None;
325	                }))
326	            }
327	
328	            (_, Event::SetValue(value)) => {
329	                let value = value.clone();
330	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
331	                    if let Some(value) = value {
332	                        ctx.value.set(value.clone());
333	                        ctx.value.sync_controlled(Some(value));
334	                    } else {
335	                        ctx.value.sync_controlled(None);
336	                    }
337	                }))
338	            }
339	
340	            (_, Event::SetProps) => Some(TransitionPlan::context_only({
341	                let feedback_duration_ms = props.feedback_duration_ms;
342	                let disabled = props.disabled;
343	
344	                move |ctx: &mut Context| {
345	                    ctx.feedback_duration_ms = feedback_duration_ms;
346	                    ctx.disabled = disabled;
347	                }
348	            })),
349	
350	            _ => None,
351	        }
352	    }
353	
354	    fn on_props_changed(old: &Props, new: &Props) -> Vec<Event> {
355	        assert_eq!(
356	            old.id, new.id,
357	            "clipboard::Props.id must remain stable after init"
358	        );
359	
360	        let mut events = Vec::new();
361	
362	        if old.value != new.value {
363	            events.push(Event::SetValue(new.value.clone()));
364	        }
365	
366	        if old.feedback_duration_ms != new.feedback_duration_ms || old.disabled != new.disabled {
367	            events.push(Event::SetProps);
368	        }
369	
370	        events
371	    }
