373	    fn connect<'a>(
374	        state: &'a Self::State,
375	        ctx: &'a Self::Context,
376	        props: &'a Self::Props,
377	        send: &'a dyn Fn(Self::Event),
378	    ) -> Self::Api<'a> {
379	        Api {
380	            state,
381	            ctx,
382	            props,
383	            send,
384	        }
385	    }
386	}
