                .trigger_attrs()
                .get(&HtmlAttr::Aria(AriaAttr::Label)),
            Some("Copied!")
        );
        assert_eq!(
            api_for_state(State::Error)
                .trigger_attrs()
                .get(&HtmlAttr::Aria(AriaAttr::Label)),
            Some("Copy failed, click to retry")
        );
    }

