        // PauseTrigger disabled unless running.
        assert!(
            !api_for(State::Running, 0, Mode::Countdown, 1_000)
                .pause_trigger_attrs()
                .contains(&HtmlAttr::Disabled)
        );
        assert!(
            api_for(State::Idle, 0, Mode::Countdown, 1_000)
