pub fn progress(&self) -> f64 {
    if self.ctx.target.is_zero() { return 0.0; }
    let fraction = self.ctx.current.as_secs_f64() / self.ctx.target.as_secs_f64();
    match self.ctx.mode {
        Mode::Countdown => 1.0 - fraction,
        Mode::Stopwatch => fraction,
    }
}

